    14→*/
    15→
    16→package u2f
    17→
    18→import (
    19→	"context"
    20→	"crypto/ecdsa"
    21→	"crypto/x509"
    22→	"time"
    23→
    24→	"github.com/flynn/u2f/u2fhid"
    25→	"github.com/flynn/u2f/u2ftoken"
    26→	"github.com/gravitational/trace"
    27→	"github.com/sirupsen/logrus"
    28→	"github.com/tstranex/u2f"
    29→
    30→	"github.com/gravitational/teleport/api/types"
    31→)
    32→
    33→// DeviceStorage is a persistent storage for MFA devices.
    34→type DeviceStorage interface {
    35→	UpsertMFADevice(ctx context.Context, key string, d *types.MFADevice) error
    36→}
    37→
    38→// NewDevice creates a U2F MFADevice object from a completed U2F registration.
    39→//
    40→// This function is not in lib/services due to an import cycle (lib/services
    41→// depends on lib/auth/u2f).
    42→func NewDevice(name string, reg *Registration, addedAt time.Time) (*types.MFADevice, error) {
    43→	d := types.NewMFADevice(name, addedAt)
    44→	pubKey, err := x509.MarshalPKIXPublicKey(&reg.PubKey)
    45→	if err != nil {
    46→		return nil, trace.Wrap(err)
    47→	}
    48→	d.Device = &types.MFADevice_U2F{U2F: &types.U2FDevice{
    49→		KeyHandle: reg.KeyHandle,
    50→		PubKey:    pubKey,
    51→	}}
    52→	if err := d.CheckAndSetDefaults(); err != nil {
    53→		return nil, trace.Wrap(err)
    54→	}
    55→	if err := ValidateDevice(d.GetU2F()); err != nil {
    56→		return nil, trace.Wrap(err)
    57→	}
    58→	return d, nil
    59→}
    60→
    61→// ValidateMFADevice validates a U2F MFA device.
    62→//
    63→// This function is not in lib/services due to an import cycle (lib/services
    64→// depends on lib/auth/u2f).
    65→func ValidateDevice(d *types.U2FDevice) error {
    66→	if len(d.KeyHandle) == 0 {
    67→		return trace.BadParameter("U2FDevice missing KeyHandle field")
    68→	}
    69→	if len(d.PubKey) == 0 {
    70→		return trace.BadParameter("U2FDevice missing PubKey field")
    71→	}
    72→	if _, err := decodeDevicePubKey(d); err != nil {
    73→		return trace.BadParameter("U2FDevice PubKey is invalid: %v", err)
    74→	}
    75→	return nil
    76→}
    77→
    78→// DeviceToRegistration decodes the U2F registration data and builds the
    79→// expected registration object.
    80→func DeviceToRegistration(d *types.U2FDevice) (*Registration, error) {
    81→	pubKey, err := decodeDevicePubKey(d)
    82→	if err != nil {
    83→		return nil, trace.Wrap(err)
    84→	}
    85→	return &u2f.Registration{
    86→		KeyHandle: d.KeyHandle,
    87→		PubKey:    *pubKey,
    88→	}, nil
    89→}
    90→
    91→func decodeDevicePubKey(d *types.U2FDevice) (*ecdsa.PublicKey, error) {
    92→	pubKeyI, err := x509.ParsePKIXPublicKey(d.PubKey)
    93→	if err != nil {
    94→		return nil, trace.Wrap(err)
    95→	}
    96→	pubKey, ok := pubKeyI.(*ecdsa.PublicKey)
    97→	if !ok {
    98→		return nil, trace.BadParameter("expected *ecdsa.PublicKey, got %T", pubKeyI)
    99→	}
   100→	return pubKey, nil
   101→}
   102→
   103→// pollLocalDevices calls fn against all local U2F devices until one succeeds
   104→// (fn returns nil) or until the context is cancelled.
   105→func pollLocalDevices(ctx context.Context, fn func(t *u2ftoken.Token) error) error {
   106→	tick := time.NewTicker(200 * time.Millisecond)
   107→	defer tick.Stop()
   108→	for {
   109→		err := foreachLocalDevice(fn)
   110→		if err == nil {
   111→			return nil
   112→		}
   113→		// Don't spam the logs while we're waiting for a key to be plugged
   114→		// in or tapped.
   115→		if err != errAuthNoKeyOrUserPresence {
   116→			logrus.WithError(err).Debugf("Error polling U2F devices for registration")
   117→		}
   118→
   119→		select {
   120→		case <-ctx.Done():
   121→			return trace.Wrap(ctx.Err())
   122→		case <-tick.C:
   123→		}
   124→	}
   125→}
   126→
   127→// foreachLocalDevice runs fn against each currently available U2F device. It
   128→// stops when fn returns nil or when finished iterating against the available
   129→// devices.
   130→//
   131→// You most likely want to call pollLocalDevices instead.
   132→func foreachLocalDevice(fn func(t *u2ftoken.Token) error) error {
   133→	// Note: we fetch and open all devices on every polling iteration on
   134→	// purpose. This will handle the device that a user inserts after the
   135→	// polling has started.
   136→	devices, err := u2fhid.Devices()
   137→	if err != nil {
   138→		return trace.Wrap(err)
   139→	}
   140→	var errs []error
   141→	for _, d := range devices {
