// TestRegression demonstrates the multi-device U2F authentication bug where
// only the first registered U2F device receives a challenge during login.
func TestRegression(t *testing.T) {
	t.Run("MultiDeviceU2FChallenge", testMultiDeviceU2FChallenge)
	t.Run("MultiDeviceU2FDeviceManagement", testMultiDeviceU2FDeviceManagement)
	t.Run("U2FChallengeForMultipleRegisteredDevices", testU2FChallengeForMultipleDevices)
}

// testMultiDeviceU2FChallenge tests that when a user has multiple U2F devices,
// challenges are created for all of them, not just the first one.
func testMultiDeviceU2FChallenge(t *testing.T) {
	ctx := context.Background()

	// Create test auth server with in-memory backend
	authServer, backendSvc := newTestAuthServer(t)
	defer backendSvc.Close()

	// Register a test user
	if err := createTestUser(t, authServer, testUser); err != nil {
		t.Fatalf("Failed to create test user: %v", err)
	}

	// Create first U2F device
	device1 := createTestU2FDevice(t, "device1", 1)
	if err := authServer.UpsertMFADevice(ctx, testUser, device1); err != nil {
		t.Fatalf("Failed to register first device: %v", err)
	}

	// Create second U2F device
	device2 := createTestU2FDevice(t, "device2", 2)
	if err := authServer.UpsertMFADevice(ctx, testUser, device2); err != nil {
		t.Fatalf("Failed to register second device: %v", err)
	}

	// Create third U2F device
	device3 := createTestU2FDevice(t, "device3", 3)
	if err := authServer.UpsertMFADevice(ctx, testUser, device3); err != nil {
		t.Fatalf("Failed to register third device: %v", err)
	}

	// Verify all devices are registered
	devices, err := authServer.GetMFADevices(ctx, testUser)
	if err != nil {
		t.Fatalf("Failed to get MFA devices: %v", err)
	}
	if len(devices) != 3 {
		t.Errorf("Expected 3 devices, got %d", len(devices))
	}

	// Test mfaAuthChallenge - should create challenges for all U2F devices
	u2fStorage, err := u2f.InMemoryAuthenticationStorage(authServer)
	if err != nil {
		t.Fatalf("Failed to create U2F storage: %v", err)
	}

	// Call mfaAuthChallenge to get challenges for all devices
	// This is the proper way to handle multiple devices
	challenge, err := authServer.(*auth.Server).MFAAuthChallenge(ctx, testUser, u2fStorage)
	if err != nil {
		t.Logf("Note: MFAAuthChallenge not directly accessible, skipping this check")
	} else {
		// The challenge should contain entries for all 3 U2F devices
		u2fChallenges := challenge.U2F
		if len(u2fChallenges) != 3 {
			t.Errorf("REGRESSION: Expected 3 U2F challenges for 3 devices, got %d", len(u2fChallenges))
		} else {
			t.Logf("PASS: mfaAuthChallenge properly creates %d challenges for %d devices", len(u2fChallenges), len(devices))
		}
	}

	// Test U2FSignRequest - this is where the bug likely is
	// It should return challenges for all devices, but likely only returns first
	t.Logf("Testing U2FSignRequest with multiple devices...")

	// First, we need to set up password authentication for the user
	password := []byte("password123")
	if err := updateUserPassword(t, authServer, testUser, password); err != nil {
		t.Fatalf("Failed to set user password: %v", err)
	}

	// Try to get U2F sign request
	// The bug: this will only return a challenge for the FIRST device
	signReq, err := authServer.U2FSignRequest(testUser, password)
	if err != nil {
		t.Logf("U2FSignRequest error (may indicate single-device limitation): %v", err)
	}

	if signReq != nil {
		// Check which device's KeyHandle we got
		keyHandles := []string{}
		for _, dev := range devices {
			u2fDev := dev.GetU2F()
			if u2fDev != nil {
				kh := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev.KeyHandle)
				keyHandles = append(keyHandles, kh)
			}
		}

		// The sign request should contain challenges for all devices
		// But due to the bug, it likely only contains the first device
		if len(keyHandles) > 1 {
			// We have multiple devices - check if U2FSignRequest returns only one
			// The API is limited and can only return a single challenge
			// This is the core of the bug!
			t.Errorf("REGRESSION: U2FSignRequest returns single challenge (%q), but user has %d U2F devices",
				signReq.KeyHandle, len(keyHandles))
			t.Logf("U2F devices registered: %v", keyHandles)
			t.Logf("Challenge received for: %q", signReq.KeyHandle)
		}
	}
}

// testMultiDeviceU2FDeviceManagement tests that adding/removing multiple devices works correctly
func testMultiDeviceU2FDeviceManagement(t *testing.T) {
	ctx := context.Background()

	// Create test auth server
	authServer, backendSvc := newTestAuthServer(t)
	defer backendSvc.Close()

	// Register a test user
	if err := createTestUser(t, authServer, testUser); err != nil {
		t.Fatalf("Failed to create test user: %v", err)
	}

	// Add first device
	device1 := createTestU2FDevice(t, "device1", 1)
	if err := authServer.UpsertMFADevice(ctx, testUser, device1); err != nil {
		t.Fatalf("Failed to add first device: %v", err)
	}

	// Verify first device exists
	devices, _ := authServer.GetMFADevices(ctx, testUser)
	if len(devices) != 1 {
		t.Errorf("Expected 1 device after adding first, got %d", len(devices))
	}

	// Add second device
	device2 := createTestU2FDevice(t, "device2", 2)
	if err := authServer.UpsertMFADevice(ctx, testUser, device2); err != nil {
		t.Fatalf("Failed to add second device: %v", err)
	}

	// Verify both devices exist
	devices, _ = authServer.GetMFADevices(ctx, testUser)
	if len(devices) != 2 {
		t.Errorf("Expected 2 devices after adding second, got %d", len(devices))
	}

	// Delete first device
	if err := authServer.DeleteMFADevice(ctx, testUser, device1.Id); err != nil {
		t.Logf("Note: DeleteMFADevice operation - may fail due to device management issues")
	}

	// Verify deletion
	devices, _ = authServer.GetMFADevices(ctx, testUser)
	if len(devices) == 1 {
		t.Logf("Device deletion successful")
	} else if len(devices) == 2 {
		t.Logf("REGRESSION: Device deletion may not have worked properly")
	}
}

// testU2FChallengeForMultipleDevices verifies challenge generation for multiple devices
func testU2FChallengeForMultipleDevices(t *testing.T) {
	ctx := context.Background()

	// Create test auth server
	authServer, backendSvc := newTestAuthServer(t)
	defer backendSvc.Close()

	// Register test user
	if err := createTestUser(t, authServer, testUser); err != nil {
		t.Fatalf("Failed to create test user: %v", err)
	}

	// Register multiple U2F devices
	device1 := createTestU2FDevice(t, "device1", 1)
	device2 := createTestU2FDevice(t, "device2", 2)
	device3 := createTestU2FDevice(t, "device3", 3)

	if err := authServer.UpsertMFADevice(ctx, testUser, device1); err != nil {
		t.Fatalf("Failed to register device1: %v", err)
	}
	if err := authServer.UpsertMFADevice(ctx, testUser, device2); err != nil {
		t.Fatalf("Failed to register device2: %v", err)
	}
	if err := authServer.UpsertMFADevice(ctx, testUser, device3); err != nil {
		t.Fatalf("Failed to register device3: %v", err)
	}

	// Create U2F authentication storage
	u2fStorage, err := u2f.InMemoryAuthenticationStorage(authServer)
	if err != nil {
		t.Fatalf("Failed to create U2F storage: %v", err)
	}

	// Test individual device challenge creation
	appID := "https://example.com"
	facets := []string{"https://example.com"}
	u2fConfig := &types.U2F{
		AppID:  appID,
		Facets: facets,
	}

	// Create challenge for each device individually
	var challenges []*u2f.AuthenticateChallenge
	for i, device := range []*types.MFADevice{device1, device2, device3} {
		challenge, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
			Dev:        device,
			AppConfig:  *u2fConfig,
			StorageKey: testUser,
			Storage:    u2fStorage,
		})
		if err != nil {
			t.Fatalf("Failed to create challenge for device %d: %v", i+1, err)
		}
		challenges = append(challenges, challenge)
		t.Logf("Device %d challenge created: KeyHandle=%q", i+1, challenge.KeyHandle)
	}

	// Verify we have challenges for all devices
	if len(challenges) != 3 {
		t.Errorf("Expected 3 challenges, got %d", len(challenges))
	}

	// Verify each challenge has a different KeyHandle
	keyHandles := make(map[string]int)
	for _, ch := range challenges {
		keyHandles[ch.KeyHandle]++
	}

	if len(keyHandles) != 3 {
		t.Errorf("REGRESSION: Expected 3 unique KeyHandles, got %d. Duplicates indicate challenge collision.", len(keyHandles))
	}

	// Verify challenges are stored correctly
	for i, device := range []*types.MFADevice{device1, device2, device3} {
		storedChallenge, err := u2fStorage.GetU2FSignChallenge(testUser, device.Id)
		if err != nil {
			t.Errorf("Failed to retrieve stored challenge for device %d: %v", i+1, err)
		} else {
			t.Logf("Device %d challenge stored and retrievable", i+1)
		}
		_ = storedChallenge
	}
}

// Helper functions

func newTestAuthServer(t *testing.T) (*auth.Server, backend.Backend) {
	backendSvc, err := memory.New(memory.Config{})
	if err != nil {
		t.Fatalf("Failed to create backend: %v", err)
	}

	authConfig := &auth.InitConfig{
		DataDir:    t.TempDir(),
		HostUUID:   "test-host",
		NodeName:   "test-node",
		Backend:    backendSvc,
		Authority:  auth.NewAuthority(),
		DomainName: "example.com",
		Clock:      clockwork.NewRealClock(),
	}

	authServer, err := auth.NewServer(authConfig)
	if err != nil {
		t.Fatalf("Failed to create auth server: %v", err)
	}

	// Set default auth preference to support U2F
	cap := &types.AuthPreference{
		Metadata: types.Metadata{
			Name:    types.MetaNameClusterAuthPreference,
			Namespace: types.DefaultNamespace,
		},
		Spec: types.AuthPreferenceSpecV2{
			Type: "u2f",
			U2F: &types.U2F{
				AppID:  "https://example.com",
				Facets: []string{"https://example.com"},
			},
		},
	}

	if err := authServer.SetAuthPreference(cap); err != nil {
		t.Fatalf("Failed to set auth preference: %v", err)
	}

	return authServer, backendSvc
}

func createTestUser(t *testing.T, authServer *auth.Server, username string) error {
	user := &types.UserV2{
		Metadata: types.Metadata{
			Name:      username,
			Namespace: types.DefaultNamespace,
		},
		Spec: types.UserSpecV2{
			Traits: map[string][]string{
				"logins": []string{username},
			},
		},
	}

	return authServer.UpsertUser(user)
}

func updateUserPassword(t *testing.T, authServer *auth.Server, username string, password []byte) error {
