// u2fDeviceToRegistration converts an MFADevice to a U2F Registration for testing
func u2fDeviceToRegistration(t *testing.T, device *types.MFADevice) *u2f.Registration {
	u2fDev := device.GetU2F()
	if u2fDev == nil {
		t.Fatalf("Device is not a U2F device")
	}

	pubKeyI, err := x509.ParsePKIXPublicKey(u2fDev.PubKey)
	if err != nil {
		t.Fatalf("Failed to parse public key: %v", err)
	}

	pubKey, ok := pubKeyI.(*ecdsa.PublicKey)
	if !ok {
		t.Fatalf("Public key is not ECDSA")
	}

	return &u2f.Registration{
		KeyHandle: u2fDev.KeyHandle,
