	}

	// Register multiple U2F devices
	device1 := createTestU2FDevice(t, "device1", 1)
	device2 := createTestU2FDevice(t, "device2", 2)
	device3 := createTestU2FDevice(t, "device3", 3)

	if err := authServer.UpsertMFADevice(ctx, testUser, device1); err != nil {
		t.Fatalf("Failed to register device1: %v", err)
	}
	if err := authServer.UpsertMFADevice(ctx, testUser, device2); err != nil {
		t.Fatalf("Failed to register device2: %v", err)
	}
	if err := authServer.UpsertMFADevice(ctx, testUser, device3); err != nil {
		t.Fatalf("Failed to register device3: %v", err)
	}

	// Create U2F authentication storage
	u2fStorage, err := u2f.InMemoryAuthenticationStorage(authServer)
	if err != nil {
		t.Fatalf("Failed to create U2F storage: %v", err)
	}

	// Get U2F config
	authPref, err := authServer.GetAuthPreference()
	if err != nil {
		t.Fatalf("Failed to get auth preference: %v", err)
	}
	u2fConfig, err := authPref.GetU2F()
	if err != nil {
		t.Fatalf("Failed to get U2F config: %v", err)
	}

	// Create individual challenges for each device
	type deviceChallenge struct {
		device    *types.MFADevice
		challenge *u2f.AuthenticateChallenge
	}
	var deviceChallenges []deviceChallenge

	for _, device := range []*types.MFADevice{device1, device2, device3} {
		challenge, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
			Dev:        device,
			AppConfig:  *u2fConfig,
			StorageKey: testUser,
			Storage:    u2fStorage,
		})
		if err != nil {
			t.Fatalf("Failed to create challenge for device %s: %v", device.Id, err)
		}
		deviceChallenges = append(deviceChallenges, deviceChallenge{device, challenge})
	}

	t.Logf("Created challenges for %d devices", len(deviceChallenges))

	// Verify each challenge was stored correctly
	for i, dc := range deviceChallenges {
		_, err := u2fStorage.GetU2FSignChallenge(testUser, dc.device.Id)
		if err != nil {
			t.Errorf("Failed to retrieve stored challenge for device %d: %v", i+1, err)
			continue
		}
		t.Logf("Device %d challenge stored and retrievable", i+1)
	}

	// Test challenge collision detection
	keyHandleMap := make(map[string]int)
	for _, dc := range deviceChallenges {
		keyHandleMap[dc.challenge.KeyHandle]++
	}

	duplicates := 0
	for _, count := range keyHandleMap {
		if count > 1 {
			duplicates++
		}
	}

	if duplicates > 0 {
		t.Errorf("REGRESSION: Detected %d duplicate KeyHandles in challenges", duplicates)
	} else {
		t.Logf("All %d challenges have unique KeyHandles", len(deviceChallenges))
	}

	// Verify challenge independence
	// Each device should be able to authenticate independently
	for i, dc := range deviceChallenges {
		// This tests that challenges are independent and not overwriting each other
		_, err := u2fStorage.GetU2FSignChallenge(testUser, dc.device.Id)
		if err != nil {
			t.Errorf("Device %d challenge not found or expired: %v", i+1, err)
		} else {
			t.Logf("Device %d challenge is independent and retrievable", i+1)
		}
	}
}

