func createTestU2FDevice(t *testing.T, name string, counter uint32) *types.MFADevice {
	// Generate a test ECDSA key pair
	privateKey, err := ecdsa.GenerateKey(elliptic.P256(), rand.Reader)
	if err != nil {
		t.Fatalf("Failed to generate key: %v", err)
	}

	// Create a unique, deterministic key handle based on the counter and name
	// This ensures each device has a different key handle
	hashInput := fmt.Sprintf("u2f-device-%s-%d-%d", name, counter, time.Now().UnixNano())
	h := sha256.Sum256([]byte(hashInput))
	keyHandle := h[:]

	// Create device
	device := types.NewMFADevice(name, time.Now())
	device.Id = fmt.Sprintf("device-id-%d", counter)

	// Marshal the public key to DER format using x509
	pubKeyDER, err := x509.MarshalPKIXPublicKey(&privateKey.PublicKey)
	if err != nil {
		t.Fatalf("Failed to marshal public key: %v", err)
	}

	device.Device = &types.MFADevice_U2F{
		U2F: &types.U2FDevice{
			KeyHandle: keyHandle,
			PubKey:    pubKeyDER,
			Counter:   counter,
		},
	}

	if err := device.CheckAndSetDefaults(); err != nil {
		t.Fatalf("Failed to set device defaults: %v", err)
	}

	return device
}

// u2fDeviceToRegistration converts an MFADevice to a U2F Registration for testing
func u2fDeviceToRegistration(t *testing.T, device *types.MFADevice) *u2f.Registration {
	u2fDev := device.GetU2F()
	if u2fDev == nil {
		t.Fatalf("Device is not a U2F device")
	}

	pubKeyI, err := x509.ParsePKIXPublicKey(u2fDev.PubKey)
	if err != nil {
		t.Fatalf("Failed to parse public key: %v", err)
	}

	pubKey, ok := pubKeyI.(*ecdsa.PublicKey)
	if !ok {
		t.Fatalf("Public key is not ECDSA")
	}

	return &u2f.Registration{
		KeyHandle: u2fDev.KeyHandle,
		PubKey:    *pubKey,
	}
}

