func u2fDeviceToRegistration(t *testing.T, device *types.MFADevice) *u2f.Registration {
	u2fDev := device.GetU2F()
	if u2fDev == nil {
		t.Fatalf("Device is not a U2F device")
	}

	pubKeyI, err := x509.ParsePKIXPublicKey(u2fDev.PubKey)
	if err != nil {
		t.Fatalf("Failed to parse public key: %v", err)
	}

	pubKey, ok := pubKeyI.(*ecdsa.PublicKey)
	if !ok {
		t.Fatalf("Public key is not ECDSA")
	}

	return &u2f.Registration{
		KeyHandle: u2fDev.KeyHandle,
		PubKey:    *pubKey,
	}
}

// regression_test.go - Test for multi-device U2F authentication bug
// This test demonstrates that when a user has multiple U2F devices registered,
// only the first device receives a challenge during authentication, preventing
// users from selecting which device to use.
package teleport

import (
	"context"
	"crypto/ecdsa"
	"crypto/elliptic"
	"crypto/rand"
	"crypto/sha256"
	"crypto/x509"
	"encoding/base64"
	"fmt"
	"testing"
	"time"

	"github.com/gravitational/teleport/api/types"
	"github.com/gravitational/teleport/lib/auth"
