// This test demonstrates that when a user has multiple U2F devices registered,
// only the first device receives a challenge during authentication, preventing
// users from selecting which device to use.
package teleport

import (
	"context"
	"crypto/ecdsa"
	"crypto/elliptic"
	"crypto/rand"
	"crypto/sha256"
	"crypto/x509"
	"encoding/base64"
	"fmt"
	"testing"
	"time"

