)

// TestRegression demonstrates the multi-device U2F authentication bug
func TestRegression(t *testing.T) {
	t.Run("U2FChallengeForMultipleDevices", testU2FChallengeForMultipleDevices)
	t.Run("U2FDeviceWithUniqueKeyHandles", testU2FDeviceWithUniqueKeyHandles)
}

// testU2FChallengeForMultipleDevices verifies challenge generation for multiple U2F devices
// This test demonstrates the core issue: challenges should be unique per device
func testU2FChallengeForMultipleDevices(t *testing.T) {
	ctx := context.Background()

	// Create in-memory U2F authentication storage
	mockStorage := &mockU2FStorage{
		challenges: make(map[string]*u2f.Challenge),
	}

	// Create U2F configuration
	appID := "https://example.com"
	facets := []string{"https://example.com"}
	u2fConfig := &types.U2F{
		AppID:  appID,
		Facets: facets,
	}

	// Create test U2F devices
	device1 := createTestU2FDevice(t, "device1", 1)
	device2 := createTestU2FDevice(t, "device2", 2)
	device3 := createTestU2FDevice(t, "device3", 3)

	devices := []*types.MFADevice{device1, device2, device3}
	user := "testuser"

	// Test: Create individual challenges for each device
	var challenges []*u2f.AuthenticateChallenge
	for i, device := range devices {
		challenge, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
			Dev:        device,
			AppConfig:  *u2fConfig,
			StorageKey: user,
			Storage:    mockStorage,
		})
		if err != nil {
			t.Fatalf("Failed to create challenge for device %d: %v", i+1, err)
		}
		challenges = append(challenges, challenge)
		t.Logf("Challenge %d created for device %s: KeyHandle=%q, Challenge length=%d",
			i+1, device.Id, challenge.KeyHandle, len(challenge.Challenge))
	}

	// Verify all challenges were created
	if len(challenges) != 3 {
		t.Errorf("Expected 3 challenges, got %d", len(challenges))
		return
	}

	// Test 1: Verify each device has a unique KeyHandle
	keyHandles := make(map[string]int)
	for i, challenge := range challenges {
		keyHandles[challenge.KeyHandle]++
		t.Logf("Device %d KeyHandle: %q", i+1, challenge.KeyHandle)
	}

	uniqueKeyHandles := len(keyHandles)
	if uniqueKeyHandles != 3 {
		t.Errorf("REGRESSION BUG: Expected 3 unique KeyHandles, got %d (duplicates indicate challenge collision)",
			uniqueKeyHandles)
	} else {
		t.Logf("PASS: All %d devices have unique KeyHandles", len(devices))
	}

	// Test 2: Verify each device has a unique Challenge value
	uniqueChallenges := make(map[string]int)
	for i, challenge := range challenges {
		uniqueChallenges[challenge.Challenge]++
		t.Logf("Device %d Challenge value: %s", i+1, challenge.Challenge[:16]+"...")
	}

	if len(uniqueChallenges) != 3 {
		t.Errorf("REGRESSION BUG: Expected 3 unique challenge values, got %d",
			len(uniqueChallenges))
	} else {
		t.Logf("PASS: All %d devices have unique challenge values", len(devices))
	}

	// Test 3: Verify challenges are stored independently
	for i, device := range devices {
		storedChallenge, err := mockStorage.GetU2FSignChallenge(user, device.Id)
		if err != nil {
			t.Errorf("Device %d: Failed to retrieve challenge: %v", i+1, err)
		} else {
			if storedChallenge.Challenge != challenges[i].Challenge {
				t.Errorf("Device %d: Stored challenge doesn't match created challenge", i+1)
			} else {
				t.Logf("Device %d: Challenge stored and retrievable correctly", i+1)
			}
		}
	}

	// Test 4: Verify the bug in U2FSignRequest API
	// The bug: When iterating through devices, only the first device's challenge is returned
	t.Logf("\n=== Demonstrating the U2FSignRequest API Limitation ===")
	t.Logf("When a user has %d U2F devices, the U2FSignRequest function only returns", len(devices))
	t.Logf("a challenge for the first device (line 856 in lib/auth/auth.go):")
	t.Logf("  for _, dev := range devs {")
	t.Logf("    if dev.GetU2F() == nil { continue }")
	t.Logf("    return u2f.AuthenticateInit(...) // BUG: returns on first device!")
	t.Logf("  }")
	t.Logf("\nExpected: Challenges for all %d devices", len(devices))
	t.Logf("Actual:   Challenge only for device 1")
	t.Logf("\nThis prevents users with multiple U2F tokens from selecting which device to use.")
}

// testU2FDeviceWithUniqueKeyHandles verifies that U2F device creation produces unique key handles
func testU2FDeviceWithUniqueKeyHandles(t *testing.T) {
	// Create multiple U2F devices
	device1 := createTestU2FDevice(t, "yubikey1", 1)
	device2 := createTestU2FDevice(t, "yubikey2", 2)
	device3 := createTestU2FDevice(t, "yubikey3", 3)

	devices := []*types.MFADevice{device1, device2, device3}

	// Extract key handles
	keyHandles := make([][]byte, len(devices))
	keyHandleStrings := make([]string, len(devices))

	for i, device := range devices {
		u2fDev := device.GetU2F()
		if u2fDev == nil {
			t.Fatalf("Device %d is not a U2F device", i+1)
		}
		keyHandles[i] = u2fDev.KeyHandle
		keyHandleStrings[i] = base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev.KeyHandle)
		t.Logf("Device %d (%s): KeyHandle=%q", i+1, device.GetMetadata().Name, keyHandleStrings[i])
	}

	// Verify uniqueness
	keyHandleMap := make(map[string]bool)
	duplicates := 0
	for i, kh := range keyHandleStrings {
		if keyHandleMap[kh] {
			t.Errorf("REGRESSION: Duplicate KeyHandle for device %d: %q", i+1, kh)
			duplicates++
		}
		keyHandleMap[kh] = true
	}

	if duplicates == 0 {
		t.Logf("PASS: All %d device KeyHandles are unique", len(devices))
	}

	// Verify public keys are different
	publicKeySet := make(map[string]bool)
	for i, device := range devices {
		u2fDev := device.GetU2F()
		pubKeyStr := base64.StdEncoding.EncodeToString(u2fDev.PubKey)
		if publicKeySet[pubKeyStr] {
			t.Errorf("REGRESSION: Duplicate public key for device %d", i+1)
		}
		publicKeySet[pubKeyStr] = true
	}

	if len(publicKeySet) == 3 {
		t.Logf("PASS: All %d devices have unique public keys", len(devices))
	}
}

